UPDATE checklist_config 
SET photo_categories = '[{"key":"painel","label":"Painel do Veículo","hint":"KM e indicadores visíveis, veículo ligado","min":1,"step":1,"ai_prompt":"Deve mostrar o painel/dashboard do veículo com o hodômetro (KM) visível e legível. O painel deve ser de um veículo automotivo real."},{"key":"exterior_frente","label":"Frente do Veículo","hint":"Foto frontal completa","min":1,"step":2,"ai_prompt":"A foto deve conter a parte dianteira de um veículo automotivo. Elementos que confirmam: capô, para-choque dianteiro, grade, faróis dianteiros, placa dianteira, logo frontal. Se QUALQUER desses elementos estiver presente, a foto é válida."},{"key":"exterior_traseira","label":"Traseira do Veículo","hint":"Foto traseira completa","min":1,"step":2,"ai_prompt":"A foto deve conter a parte traseira de um veículo automotivo. Elementos que confirmam: para-choque traseiro, lanternas traseiras, placa traseira, porta-malas, logo traseiro. Se QUALQUER desses elementos estiver presente, a foto é válida."},{"key":"exterior_esquerda","label":"Lateral Esquerda","hint":"Foto lateral esquerda completa","min":1,"step":2,"ai_prompt":"A foto deve mostrar o PERFIL LATERAL ESQUERDO COMPLETO do veículo de forma que seja possível inspecionar a lataria inteira. REQUISITOS OBRIGATÓRIOS: (1) A foto deve ser tirada de uma POSIÇÃO LATERAL, com o fotógrafo ao lado do carro, aproximadamente na altura da cintura/peito. (2) O veículo deve aparecer na HORIZONTAL. (3) A lateral deve estar QUASE TODA visível. (4) Não pode haver corte relevante nas extremidades. (5) A imagem deve permitir avaliar possíveis amassados, riscos e avarias. REJEITE se: foto de cima, carro rotacionado/diagonal, lateral cortada, ou ângulo que impeça avaliar paralamas."},{"key":"exterior_direita","label":"Lateral Direita","hint":"Foto lateral direita completa","min":1,"step":2,"ai_prompt":"A foto deve mostrar o PERFIL LATERAL DIREITO COMPLETO do veículo de forma que seja possível inspecionar a lataria inteira. REQUISITOS OBRIGATÓRIOS: (1) A foto deve ser tirada de uma POSIÇÃO LATERAL, com o fotógrafo ao lado do carro, aproximadamente na altura da cintura/peito. (2) O veículo deve aparecer na HORIZONTAL. (3) A lateral deve estar QUASE TODA visível. (4) Não pode haver corte relevante nas extremidades. (5) A imagem deve permitir avaliar possíveis amassados, riscos e avarias. REJEITE se: foto de cima, carro rotacionado/diagonal, lateral cortada, ou ângulo que impeça avaliar paralamas."},{"key":"nivel_oleo","label":"Nível de Óleo","hint":"Foto da vareta ou indicador de nível","min":1,"step":4,"ai_prompt":"Deve mostrar a vareta de óleo do motor com o NÍVEL DO ÓLEO visível. A vareta deve estar fora do motor e o óleo deve ser visível na ponta da vareta. Se o óleo estiver ABAIXO da marca MIN ou não for possível identificar o nível na vareta, marque critical_visible=false."},{"key":"reservatorio_agua","label":"Reservatório de Água","hint":"Foto do reservatório de arrefecimento","min":1,"step":4,"ai_prompt":"Deve mostrar o reservatório de água/arrefecimento do veículo. ACEITE se o reservatório estiver visível e identificável, mesmo com nível pouco claro. Só REJEITE se a foto não mostrar o reservatório ou ele estiver CLARAMENTE vazio/seco."},{"key":"pneu_de","label":"Pneu Dianteiro Esquerdo","hint":"Foto mostrando banda de rodagem","min":1,"step":3,"ai_prompt":"Deve mostrar claramente o pneu dianteiro esquerdo com condição visual da banda de rodagem minimamente verificável."},{"key":"pneu_dd","label":"Pneu Dianteiro Direito","hint":"Foto mostrando banda de rodagem","min":1,"step":3,"ai_prompt":"Deve mostrar claramente o pneu dianteiro direito com condição visual da banda de rodagem minimamente verificável."},{"key":"pneu_te","label":"Pneu Traseiro Esquerdo","hint":"Foto mostrando banda de rodagem","min":1,"step":3,"ai_prompt":"Deve mostrar claramente o pneu traseiro esquerdo com condição visual da banda de rodagem minimamente verificável."},{"key":"pneu_td","label":"Pneu Traseiro Direito","hint":"Foto mostrando banda de rodagem","min":1,"step":3,"ai_prompt":"Deve mostrar claramente o pneu traseiro direito com condição visual da banda de rodagem minimamente verificável."},{"key":"calibracao","label":"Calibração dos Pneus","hint":"Foto do calibrador mostrando pressão","min":1,"step":3,"ai_prompt":"Deve mostrar o calibrador/medidor de pressão de pneus com o valor visível e legível."},{"key":"estepe","label":"Pneu Estepe","hint":"Foto mostrando condição do estepe","min":1,"step":3,"ai_prompt":"Deve mostrar o pneu estepe (pneu reserva) do veículo de forma identificável."},{"key":"farois_lanternas","label":"Faróis e Lanternas","hint":"Faróis acesos, setas funcionando","min":1,"step":2,"ai_prompt":"A foto deve mostrar faróis OU lanternas de um veículo. NÃO exija close-up. Uma foto do veículo de frente ou de trás CONTÉM faróis/lanternas por definição."},{"key":"motor","label":"Compartimento do Motor","hint":"Foto do motor aberto","min":1,"step":4,"ai_prompt":"Deve mostrar o compartimento do motor do veículo com o capô aberto."},{"key":"itens_seguranca","label":"Itens de Segurança","hint":"Triângulo, macaco, chave de roda visíveis","min":1,"step":3,"ai_prompt":"A foto DEVE mostrar os três itens de segurança obrigatórios: triângulo de sinalização, macaco hidráulico/mecânico e chave de roda. Só afirme que um item está presente se conseguir IDENTIFICÁ-LO COM CERTEZA. Se a foto está escura ou desfocada, NÃO ADIVINHE. NUNCA invente ou suponha. Para aceitar, os 3 itens devem ser CLARAMENTE visíveis."},{"key":"interior","label":"Interior do Veículo","hint":"Foto da organização e limpeza interna","min":1,"step":5,"ai_prompt":"A foto deve mostrar uma VISÃO AMPLA do interior do veículo. Pelo menos 2 elementos devem ser visíveis: bancos dianteiros, bancos traseiros, painel/console ou forros de porta. REJEITE se mostra apenas um elemento isolado, ângulo fechado ou objetos cobrindo superfícies."},{"key":"danos","label":"Registro de Dano/Avaria","hint":"Foto detalhada do dano encontrado","min":1,"step":6,"ai_prompt":"Deve mostrar claramente o dano, avaria ou defeito no veículo. O dano deve ser visível."},{"key":"avaria","label":"Nova Avaria","hint":"Foto obrigatória da avaria encontrada","min":1,"step":6,"ai_prompt":"Deve mostrar claramente o dano, avaria ou defeito no veículo. O dano deve ser visível."}]'::jsonb,
    updated_at = now()
WHERE config_key = 'default';